(() => {
  const BUTTON = 'AI指引';
  const LONG_PRESS_MS = 500;
  const MOVE_TOLERANCE = 12;

  function api() {
    return window.parent.STAISuggestion;
  }

  function toast(message, type = 'info') {
    const t = window.parent.toastr || window.toastr || globalThis.toastr;
    if (t && (t[type] || t.info)) {
      (t[type] || t.info)(message);
    } else {
      console[type === 'error' ? 'error' : 'log']('[AI指引助手] ' + message);
    }
  }

  function runGenerate() {
    const helper = api();
    if (!helper || typeof helper.generate !== 'function') {
      toast('AI指引助手插件尚未就绪，请确认扩展已启用。', 'warning');
      return;
    }
    helper.generate();
  }

  function runOutline() {
    const helper = api();
    if (!helper || typeof helper.openOutline !== 'function') {
      toast('AI指引助手插件尚未就绪，请确认扩展已启用。', 'warning');
      return;
    }
    helper.openOutline();
  }

  appendInexistentScriptButtons([{ name: BUTTON, visible: true }]);
  eventOn(getButtonEvent(BUTTON), runGenerate);

  function bindLongPress() {
    const scriptId = window.__TH_IFRAME_ID || window.frameElement?.id || '';
    const root = window.parent.document.getElementById('script_container_' + scriptId);
    if (!root) return false;

    const button = Array.from(root.querySelectorAll('.qr--button')).find(el => el.textContent.trim() === BUTTON);
    if (!button || button.dataset.aiSuggestionLongPressBound === '1') return !!button;
    button.dataset.aiSuggestionLongPressBound = '1';
    button.title = '点击生成回复建议，长按输入大纲';

    let timer = null;
    let startX = 0;
    let startY = 0;
    let suppressClick = false;

    const clearTimer = () => {
      if (timer) {
        clearTimeout(timer);
        timer = null;
      }
    };

    button.addEventListener('pointerdown', event => {
      if (event.button !== undefined && event.button !== 0) return;
      startX = event.clientX;
      startY = event.clientY;
      suppressClick = false;
      clearTimer();
      timer = setTimeout(() => {
        suppressClick = true;
        runOutline();
      }, LONG_PRESS_MS);
    }, true);

    button.addEventListener('pointermove', event => {
      if (!timer) return;
      const dx = Math.abs(event.clientX - startX);
      const dy = Math.abs(event.clientY - startY);
      if (dx > MOVE_TOLERANCE || dy > MOVE_TOLERANCE) clearTimer();
    }, true);

    button.addEventListener('pointerup', clearTimer, true);
    button.addEventListener('pointercancel', clearTimer, true);
    button.addEventListener('pointerleave', clearTimer, true);
    button.addEventListener('click', event => {
      if (!suppressClick) return;
      suppressClick = false;
      event.preventDefault();
      event.stopImmediatePropagation();
    }, true);

    return true;
  }

  if (!bindLongPress()) {
    const interval = setInterval(() => {
      if (bindLongPress()) clearInterval(interval);
    }, 500);
    setTimeout(() => clearInterval(interval), 15000);
  }
})();
